import re

# Get civic documents path
civic_file = locals()['var_functions.query_db:5']

# Read civic documents
with open(civic_file, 'r') as f:
    civic_docs = json.load(f)

# Get funding data
funding_file = locals()['var_functions.execute_python:12']
with open('/tmp/tmp7n9h5nnq.json', 'r') as f:
    funding_data = json.load(f)

funding_names = [name.lower() for name in funding_data['project_names']]

# Find design projects
all_design_projects = []

for doc in civic_docs:
    text = doc.get('text', '').lower()

    # Find where design projects are listed
    start = text.find('capital improvement projects (design)')
    if start == -1:
        continue

    # Look until the next section
    end = text.find('capital improvement projects (construction)', start)
    if end == -1:
        end = text.find('disaster recovery projects', start)
    if end == -1:
        end = len(text)

    design_section = text[start:end]

    # Split into lines and look for project names
    for line in design_section.split('\n'):
        line = line.strip()
        if len(line) < 10:
            continue
        if line.startswith('(') or 'cid:' in line:
            continue
        if any(x in line for x in ['project schedule', 'updates:', 'complete design']):
            continue

        # Check if it looks like a project name
        if any(term in line for term in ['road', 'drive', 'project', 'repair', 'drain', 'park', 'walkway', 'malibu', 'canyon', 'pch', 'improvement']):
            # Clean up
            clean = line.title()
            clean = re.sub(r'^\d+\s*\.\s*', '', clean)
            clean = re.sub(r'\s+', ' ', clean)
            if len(clean) > 10:
                all_design_projects.append(clean)

# Remove duplicates
unique_design = list(set(all_design_projects))

# Match with funding projects
matches = []
for design_proj in unique_design:
    design_lower = design_proj.lower()
    if design_lower in funding_names:
        matches.append(design_proj)
    else:
        # Try partial matching for cases like "PCH Median Improvements" vs "PCH Median Improvements Project"
        for funded in funding_data['project_names']:
            funded_lower = funded.lower()
            if (design_lower in funded_lower or funded_lower in design_lower) and abs(len(design_proj) - len(funded)) < 15:
                matches.append(design_proj)
                break

result = {
    'design_projects_found': len(unique_design),
    'funded_design_projects': len(matches),
    'matches': matches
}

print('__RESULT__:')
print(json.dumps(result))"}

